import {
  AppBar,
  Box,
  Container,
  Tab,
  Tabs,
  Toolbar,
  Typography,
  useMediaQuery,
  useTheme,
} from '@mui/material';
import i18next from 'i18next';
import Image from 'next/image';
import Link from 'next/link';
import { ReactNode, useEffect, useMemo, useState } from 'react';

import AppConstants from '@/constants/app.constants';
import { PAGE_INFO } from '@/constants/page.constants';
import useServicesHook from '@/hooks';
import { translate } from '@/utils/i18n';

export default function DocumentsLayout({
  children,
  tab,
}: {
  children: ReactNode;
  tab: 'terms' | 'privacy';
}) {
  const { router } = useServicesHook();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));
  const [updateKey, setUpdateKey] = useState(0);

  const tabValueToPath: Record<string, string> = useMemo(() => {
    return {
      terms: PAGE_INFO.TERMS_OF_USE.href(),
      privacy: PAGE_INFO.PRIVACY_POLICY.href(),
    };
  }, []);

  // 言語変更を監視して i18next を更新し、再レンダリングをトリガー
  useEffect(() => {
    const lang = router.query.lang as string;
    if (lang && i18next.language !== lang) {
      i18next.changeLanguage(lang).then(() => {
        setUpdateKey((prev) => prev + 1);
      });
    }
  }, [router.query.lang]);

  const onTabChanged = (value: string) => {
    // 現在のクエリパラメータから言語設定を取得
    const currentLang = router.query.lang as string;
    const path = tabValueToPath[value.toString()];
    // 言語パラメータがある場合は維持
    const url = currentLang ? `${path}?lang=${currentLang}` : path;
    router.push(url);
  };
  return (
    <Box
      sx={{
        display: 'flex',
        flexDirection: 'column',
        position: 'relative',
      }}
    >
      <AppBar
        color="inherit"
        position="fixed"
        sx={(theme) => ({
          boxShadow: `inset 0 -2px ${theme.palette.divider}`,
        })}
      >
        <Container maxWidth="lg">
          <Toolbar variant="dense">
            <Link href="/" passHref style={{ textDecoration: 'none' }}>
              <Box
                sx={{
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                }}
              >
                <Image
                  src={AppConstants.LOGO_URL}
                  alt=""
                  priority={true}
                  height={50}
                  width={200}
                />
              </Box>
            </Link>
          </Toolbar>
        </Container>
      </AppBar>
      <Toolbar />
      <Container
        maxWidth="lg"
        sx={{ display: 'flex', flex: 1, flexDirection: 'column', minHeight: 0 }}
      >
        <Box
          sx={{
            display: 'flex',
            flex: 1,
            minHeight: 0,
            pt: 2,
            px: { xs: 0, sm: 1 },
            flexDirection: isMobile ? 'column' : 'row',
          }}
        >
          <Tabs
            key={updateKey}
            orientation={isMobile ? 'horizontal' : 'vertical'}
            sx={{
              minWidth: isMobile ? 'auto' : '18rem',
              borderBottom: isMobile ? 1 : 0,
              borderRight: isMobile ? 0 : 1,
              borderColor: 'divider',
              mb: isMobile ? 2 : 0,
            }}
            value={tab}
            onChange={(_, newValue) => onTabChanged(`${newValue}`)}
            variant={isMobile ? 'fullWidth' : 'standard'}
          >
            <Tab label={translate('terms_of_use')} value="terms" />
            <Tab label={translate('privacy_policy')} value="privacy" />
          </Tabs>
          <Box sx={{ flex: 1, overflow: 'auto', px: { xs: 2, sm: 0 } }}>
            {children}
          </Box>
        </Box>
      </Container>
      <Box
        sx={(theme) => ({
          alignItems: 'center',
          boxShadow: `inset 0 2px ${theme.palette.divider}`,
          display: 'flex',
          justifyContent: 'center',
          minHeight: '4rem',
        })}
      >
        <Typography>©2025 Knowhere, Inc.</Typography>
      </Box>
    </Box>
  );
}

